#include<bits/stdc++.h>
using namespace std;
const int N=100010;
int n,val[N],top[N],dfn[N],dfncnt,fa[N],siz[N],rnk[N],son[N],d[N],mod;
vector<int> mp[N];
void dfs1(int x,int f=0)
{
    fa[x]=f;
    siz[x]=1;
    son[x]=-1;
    for(int i:mp[x])
    {
        if(i!=f)
        {
            d[i]=d[x]+1;
            dfs1(i,x);
            siz[x]+=siz[i];
            if(son[x]==-1||siz[i]>siz[son[x]])
            {
                son[x]=i;
            }
        }
    }
}
void dfs2(int x,int t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(int i:mp[x])
        {
            if(i!=fa[x]&&i!=son[x])
            {
                dfs2(i,i);
            }
        }
    }
}
struct segment_tree
{
    struct node
    {
        int l,r;
        int lson,rson;
        int sum,tag;
    }a[N*3];
    int cnt;
    segment_tree():cnt(0){}
    void pushup(int x)
    {
        a[x].sum=(a[a[x].lson].sum+a[a[x].rson].sum)%mod;
    }
    void pushadd(int x,int v)
    {
        if(!x)
        {
            return;
        }
        a[x].sum=(a[x].sum+(a[x].r-a[x].l+1)*v%mod)%mod;
        a[x].tag=(a[x].tag+v)%mod;
    }
    void pushdown(int x)
    {
        int ls=a[x].lson,rs=a[x].rson;
        int tg=a[x].tag;
        pushadd(ls,tg);
        pushadd(rs,tg);
        a[x].tag=0;
    }
    int init(int l,int r)
    {
        int x=++cnt;
        a[x].l=l;
        a[x].r=r;
        a[x].tag=0;
        if(l==r)
        {
            a[x].sum=val[rnk[l]];
            return x;
        }
        int mid=(l+r)>>1;
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(int x,int l,int r,int v)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            pushadd(x,v);
            return;
        }
        pushdown(x);
        add(a[x].lson,l,r,v);
        add(a[x].rson,l,r,v);
        pushup(x);
    }
    int query(int x,int l,int r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        pushdown(x);
        return (query(a[x].lson,l,r)+query(a[x].rson,l,r))%mod;
    }
}t;
void add(int x,int y,int v)
{
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        t.add(1,dfn[top[x]],dfn[x],v);
        x=fa[top[x]];
    }
    if(dfn[x]>dfn[y])
    {
        swap(x,y);
    }
    t.add(1,dfn[x],dfn[y],v);
}
int getsum(int x,int y)
{
    int ans=0;
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        ans+=t.query(1,dfn[top[x]],dfn[x]);
        ans%=mod;
        x=fa[top[x]];
    }
    if(dfn[x]>dfn[y])
    {
        swap(x,y);
    }
    ans+=t.query(1,dfn[x],dfn[y]);
    ans%=mod;
    return ans;
}
int main()
{
    int m,r;
    scanf("%d%d%d%d",&n,&m,&r,&mod);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&val[i]);
        val[i]%=mod;
    }
    for(int i=1;i<n;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    dfs1(r);
    dfs2(r,r);
    t.init(1,n);
    while(m--)
    {
        int op,x,y,z;
        scanf("%d%d",&op,&x);
        if(op==1)
        {
            scanf("%d%d",&y,&z);
            add(x,y,z);
        }
        else if(op==2)
        {
            scanf("%d",&y);
            printf("%d\n",getsum(x,y));
        }
        else if(op==3)
        {
            scanf("%d",&z);
            t.add(1,dfn[x],dfn[x]+siz[x]-1,z);
        }
        else if(op==4)
        {
            printf("%d\n",t.query(1,dfn[x],dfn[x]+siz[x]-1));
        }
    }
    return 0;
}
